parameters.jsCode:
return [{ json: {
  week: 'July 14–18, 2026',
  role: 'Head of Product',
  okrs_this_quarter: [
    'OKR1: Reduce time-to-first-value from 14 days to 7 days (KR: 60% of new signups complete onboarding in ≤7 days)',
    'OKR2: Improve NPS from 38 to 50 (KR: NPS ≥50 by EoQ)',
    'OKR3: Launch recurring tasks feature (KR: GA release by July 31)'
  ],
  top_backlog_items: [
    { id: 'P-412', title: 'Recurring tasks: final QA pass and smoke test', estimate: '1d', urgency: 'high', linked_okr: 'OKR3' },
    { id: 'P-421', title: 'Onboarding flow redesign: review Figma mockups with design', estimate: '2h', urgency: 'high', linked_okr: 'OKR1' },
    { id: 'P-389', title: 'Write spec for bulk task actions (v1)', estimate: '3h', urgency: 'medium', linked_okr: 'OKR2' },
    { id: 'P-401', title: 'Review user research synthesis from Q3 study', estimate: '1.5h', urgency: 'medium', linked_okr: 'OKR1' },
    { id: 'P-415', title: 'Stakeholder update deck for board prep', estimate: '2h', urgency: 'high', linked_okr: null }
  ],
  committed_deliverables: [
    'Recurring tasks release notes final draft by Wednesday',
    'Board deck draft to CEO by Friday'
  ],
  key_meetings: [
    { day: 'Monday', meeting: 'Sprint planning 2h', type: 'engineering' },
    { day: 'Tuesday', meeting: 'Customer discovery call 1h', type: 'research' },
    { day: 'Thursday', meeting: 'CEO 1:1 30m', type: 'internal' },
    { day: 'Friday', meeting: 'Team retro 1h', type: 'team' }
  ],
  focus_hours_available: 20,
  last_week_carry_over: 'Spec for bulk actions was not started last week'
} }];

const ctx = $input.first().json;
const okrText = ctx.okrs_this_quarter.map((o,i) => `  ${o}`).join('
');
const backlogText = ctx.top_backlog_items.map(b => `  [${b.urgency.toUpperCase()}] ${b.id}: ${b.title} (${b.estimate})${b.linked_okr ? ' → '+b.linked_okr : ''}`).join('
');
const commitText = ctx.committed_deliverables.map(c => `  • ${c}`).join('
');
const mtgText = ctx.key_meetings.map(m => `  ${m.day}: ${m.meeting}`).join('
');
const system = `You are an executive coach and product leadership advisor. You help PMs prioritise their week with ruthless clarity: what to do, what to defer, what to delegate, and how to protect focus time. You always tie priorities back to OKRs and flag risks. Return ONLY valid JSON.`;
const user = `Create a weekly priority plan for: ${ctx.role} | ${ctx.week}
Available focus hours: ${ctx.focus_hours_available}h

OKRs this quarter:
${okrText}

Top backlog items:
${backlogText}

Committed deliverables:
${commitText}

Key meetings (already scheduled):
${mtgText}

Carry-over from last week: ${ctx.last_week_carry_over}

Return JSON:
{
  "weekly_theme": "string — a 5-10 word statement of what this week is about",
  "top_3_priorities": [
    {
      "rank": 1,
      "item": "string",
      "why_this_week": "string",
      "linked_okr": "string|null",
      "estimated_hours": 3,
      "suggested_day": "string"
    }
  ],
  "defer_list": [{"item": "string", "reason": "string"}],
  "delegate_list": [{"item": "string", "to": "string", "reason": "string"}],
  "risks_this_week": ["string"],
  "focus_time_allocation": {"okr_work_hours": 12, "admin_hours": 4, "meetings_hours": 4},
  "end_of_week_success_criteria": ["string"]
}`;
return [{ json: { ctx, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Planning Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.top_3_priorities || !Array.isArray(parsed.top_3_priorities)) return [{ json: { _error: true, reason: 'Missing top_3_priorities' } }];
return [{ json: { _error: false, plan: parsed, ctx: upstream.ctx, meta: { week: upstream.ctx.week, generated_at: new Date().toISOString() } } }];
